const ANTHROPIC_API_KEY = 'PASTE_YOUR_KEY_HERE';

async function claude(prompt, maxTokens) {
  const bodyStr = JSON.stringify({
    model: 'claude-haiku-4-5-20251001',
    max_tokens: maxTokens,
    messages: [{ role: 'user', content: prompt }]
  });
  const result = await new Promise((resolve, reject) => {
    const req = require('https').request({
      hostname: 'api.anthropic.com', path: '/v1/messages', method: 'POST',
      headers: { 'x-api-key': ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json', 'content-length': Buffer.byteLength(bodyStr) }
    }, res => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve({ status: res.statusCode, body: d })); });
    req.on('error', reject); req.write(bodyStr); req.end();
  });
  if (result.status !== 200) throw new Error('Claude ' + result.status + ': ' + result.body);
  return JSON.parse(result.body).content[0].text.trim();
}

const body = $input.first().json.body || $input.first().json;
const title = body.title || '';
const description = body.description || '';

const text = await claude(
  'Create a product brief for this SaaS idea. Return ONLY valid JSON, no markdown.\n\nIdea: ' + title + '\nDescription: ' + description + '\n\n{\n  "productName": "Short name",\n  "tagline": "One line pitch",\n  "problem": "2 sentence problem",\n  "solution": "2 sentence solution",\n  "targetAudience": "specific audience",\n  "domain": "suggested-domain.com",\n  "pricing": [{"plan":"Starter","price":"$29/mo","features":["f1","f2","f3"]},{"plan":"Pro","price":"$79/mo","features":["f1","f2","f3","f4"]}],\n  "features": ["feature 1","feature 2","feature 3","feature 4","feature 5","feature 6"],\n  "techStack": ["Next.js 14","TypeScript","Tailwind CSS","Supabase","Stripe"],\n  "dbTables": ["users","subscriptions","main_entity"],\n  "mainEntity": "the core data model name (e.g. appointments, tasks, invoices)",\n  "coreRoutes": ["/","/dashboard","/dashboard/[main]","/api/[main]"]\n}',
  1200
);

const match = text.match(/\{[\s\S]*\}/);
if (!match) throw new Error('No JSON in brief response: ' + text.slice(0, 300));
const brief = JSON.parse(match[0]);

return [{ json: { ...brief, ideaId: body.ideaId, ideaTitle: title, generatedAt: new Date().toISOString() } }];

