const fs = require('fs');
const path = require('path');
const d = $input.first().json;

const slug = (d.productName || 'product').toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-');
const projectDir = 'C:/autonomy-launches/' + slug;
const entity = d.mainEntity || 'items';

// Build file map
const files = [
  { path: 'package.json',        content: d.packageJsonCode },
  { path: 'tsconfig.json',       content: d.tsConfigCode },
  { path: 'next.config.ts',      content: d.nextConfigCode },
  { path: 'tailwind.config.ts',  content: d.tailwindConfigCode },
  { path: 'postcss.config.js',   content: d.postcssConfigCode },
  { path: 'app/globals.css',     content: d.globalsCode },
  { path: 'app/layout.tsx',      content: d.layoutCode },
  { path: 'app/page.tsx',        content: d.landingCode },
  { path: 'app/dashboard/layout.tsx',   content: d.dashLayoutCode },
  { path: 'app/dashboard/page.tsx',     content: d.dashPageCode },
  { path: 'app/dashboard/settings/page.tsx', content: d.settingsPageCode },
  { path: 'app/dashboard/' + entity + '/page.tsx', content: d.corePageCode },
  { path: 'app/api/' + entity + '/route.ts',       content: d.apiRouteCode },
  { path: 'app/api/' + entity + '/[id]/route.ts',  content: d.apiItemRouteCode },
  { path: 'supabase/schema.sql', content: d.schemaCode },
  { path: '.env.example',        content: d.envExampleCode },
  { path: 'README.md',           content: d.readmeCode },
].filter(f => f.content);

// Save all files
if (!fs.existsSync(projectDir)) fs.mkdirSync(projectDir, { recursive: true });

const savedFiles = [];
for (const file of files) {
  const fullPath = path.join(projectDir, file.path);
  const dir = path.dirname(fullPath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(fullPath, file.content, 'utf8');
  savedFiles.push(file.path);
}

// Save brief (metadata without code)
const brief = {
  productName: d.productName, tagline: d.tagline,
  problem: d.problem, solution: d.solution,
  targetAudience: d.targetAudience, domain: d.domain,
  pricing: d.pricing, features: d.features,
  techStack: d.techStack, mainEntity: d.mainEntity,
  ideaId: d.ideaId, ideaTitle: d.ideaTitle,
  generatedAt: d.generatedAt, slug, savedFiles
};
fs.writeFileSync(path.join(projectDir, 'brief.json'), JSON.stringify(brief, null, 2), 'utf8');

// Update registry
if (!fs.existsSync('C:/autonomy-data')) fs.mkdirSync('C:/autonomy-data', { recursive: true });
const registryPath = 'C:/autonomy-data/launches.json';
let launches = [];
try { launches = JSON.parse(fs.readFileSync(registryPath, 'utf8')); } catch(e) {}

const existing = launches.findIndex(l => l.slug === slug);
const entry = {
  id: existing >= 0 ? launches[existing].id : Date.now(),
  ideaId: d.ideaId, ideaTitle: d.ideaTitle,
  productName: d.productName, tagline: d.tagline,
  slug, domain: d.domain, status: 'generated',
  projectDir, savedFiles,
  generatedAt: d.generatedAt
};
if (existing >= 0) launches[existing] = entry;
else launches.push(entry);
fs.writeFileSync(registryPath, JSON.stringify(launches, null, 2), 'utf8');

return [{
  json: {
    success: true,
    productName: d.productName,
    tagline: d.tagline,
    slug, projectDir,
    domain: d.domain,
    savedFiles,
    filesCount: savedFiles.length,
    generatedAt: d.generatedAt
  }
}];
